assembly ("memory-safe") {
    let A_ := mulmod(mload(add(pPoint1_, 0x40)), mload(add(pPoint2_, 0x40)), p_)
    let B_ := mulmod(A_, A_, p_)
    let C_ := mulmod(mload(pPoint1_), mload(pPoint2_), p_)
    let D_ := mulmod(mload(add(pPoint1_, 0x20)), mload(add(pPoint2_, 0x20)), p_)
    let E_ := mulmod(d_, mulmod(C_, D_, p_), p_)
    let F_ := addmod(B_, sub(p_, E_), p_)
    B_ := addmod(B_, E_, p_)
    let H_ := mulmod(
        addmod(mload(pPoint1_), mload(add(pPoint1_, 0x20)), p_),
        addmod(mload(pPoint2_), mload(add(pPoint2_, 0x20)), p_),
        p_
    )
    H_ := addmod(addmod(H_, sub(p_, C_), p_), sub(p_, D_), p_)
    C_ := addmod(D_, sub(p_, mulmod(a_, C_, p_)), p_)

    mstore(pPoint3_, mulmod(F_, mulmod(A_, H_, p_), p_))
    mstore(add(pPoint3_, 0x20), mulmod(B_, mulmod(A_, C_, p_), p_))
    mstore(add(pPoint3_, 0x40), mulmod(F_, B_, p_))
}

for (uint256 i = 2; i < proof_.siblingsLength; i += 2) {
    bytes32 parentKey_ = proof_.siblings[proof_.siblingsLength - i - 2];

    if (!proof_.existence) {
        if (
            proof_.key == parentKey_ ||
            (proof_.key < parentKey_ && proof_.nonExistenceKey >= parentKey_) ||
            (proof_.key > parentKey_ && proof_.nonExistenceKey <= parentKey_)
        ) {
            return ZERO_HASH;
        }
    }

    directionBit_ = _extractDirectionBit(proof_.directionBits, i);

    leftHash_ = computedHash_;
    rightHash_ = proof_.siblings[proof_.siblingsLength - i - 1];

    if (directionBit_) {
        (leftHash_, rightHash_) = (rightHash_, leftHash_);
    }

    computedHash_ = hash3_(parentKey_, leftHash_, rightHash_);
}

for (uint256 i = 0; i < levelsCount_; i++) {
    bytes32 currentLevelNodeHash_;

    if (i == LEAVES_LEVEL) {
        currentLevelNodeHash_ = _hashLeaf(
            levelIndex_,
            leafData_.value,
            leafData_.nextLeafIndex,
            true,
            hashFunctions_.hash4
        );
    } else {
        currentLevelNodeHash_ = _calculateNodeHash(tree, levelIndex_, i, hashFunctions_);
    }

    if (levelIndex_ == _getLevelNodesCount(tree, i)) {
        tree.nodes[i].push(currentLevelNodeHash_);
    } else {
        tree.nodes[i][levelIndex_] = currentLevelNodeHash_;
    }

    if (i + 1 == levelsCount_ && _getLevelNodesCount(tree, i) > 1) {
        levelsCount_++;
    }

    levelIndex_ /= 2;
}

if (currentNode_.nodeType == NodeType.EMPTY) {
    return _setNode(tree, newLeaf_);
} else if (currentNode_.nodeType == NodeType.LEAF) {
    if (currentNode_.key == newLeaf_.key) revert KeyAlreadyExists(newLeaf_.key);

    return _pushLeaf(tree, newLeaf_, currentNode_, nodeId_, currentDepth_);
} else {
    uint256 nextNodeId_;

    if ((uint256(newLeaf_.key) >> currentDepth_) & 1 == 1) {
        nextNodeId_ = _add(tree, newLeaf_, currentNode_.childRight, currentDepth_ + 1);

        tree.nodes[nodeId_].childRight = uint64(nextNodeId_);
    } else {
        nextNodeId_ = _add(tree, newLeaf_, currentNode_.childLeft, currentDepth_ + 1);

        tree.nodes[nodeId_].childLeft = uint64(nextNodeId_);
    }

    tree.nodes[nodeId_].nodeHash = _getNodeHash(tree, tree.nodes[nodeId_]);

    return nodeId_;
}

if (claimedSigner.code.length == 0) {
    if (signature.length == 65) {
        (r, s) = abi.decode(signature, (bytes32, bytes32));
        v = uint8(signature[64]);
    } else if (signature.length == 64) {
        // EIP-2098
        bytes32 vs;
        (r, vs) = abi.decode(signature, (bytes32, bytes32));
        s = vs & UPPER_BIT_MASK;
        v = uint8(uint256(vs >> 255)) + 27;
    } else {
        revert InvalidSignatureLength();
    }
    address signer = ecrecover(hash, v, r, s);
    if (signer == address(0)) revert InvalidSignature();
    if (signer != claimedSigner) revert InvalidSigner();
} else {
    bytes4 magicValue = IERC1271(claimedSigner).isValidSignature(hash, signature);
    if (magicValue != IERC1271.isValidSignature.selector) revert InvalidContractSignature();
}

assembly {
    let l := mload(signature)
    for {} 1 {} {
        mstore(0x00, mload(add(signature, 0x20))) // `r`.
        let s := mload(add(signature, 0x40))
        let v := mload(add(signature, 0x41))
        if eq(l, 64) {
            v := add(shr(255, s), 27)
            s := shr(1, shl(1, s))
        }
        if iszero(lt(s, _HALF_N_PLUS_1)) {
            v := xor(v, 7)
            s := sub(N, s)
        }
        mstore(0x21, v)
        mstore(0x20, s)
        result := keccak256(0x00, 0x41)
        mstore(0x21, 0) // Restore the overwritten part of the free memory pointer.
        break
    }

    // If the length is neither 64 nor 65, return a uniquely corrupted hash.
    if iszero(lt(sub(l, 64), 2)) {
        // `bytes4(keccak256("InvalidSignatureLength"))`.
        result := xor(keccak256(add(signature, 0x20), l), 0xd62f1ab2)
    }
}

assembly {
    value := shr(96, shl(96, value))
    if eq(value, _ZERO_SENTINEL) {
        mstore(0x00, 0xf5a267f1) // `ValueIsZeroSentinel()`.
        revert(0x1c, 0x04)
    }
    if iszero(value) { value := _ZERO_SENTINEL }
    let rootPacked := sload(rootSlot)
    for {} 1 {} {
        if iszero(shr(160, shl(160, rootPacked))) {
            result := 1
            if eq(shr(96, rootPacked), value) { break }
            if eq(shr(96, sload(add(rootSlot, 1))), value) { break }
            if eq(shr(96, sload(add(rootSlot, 2))), value) { break }
            result := 0
            break
        }
        mstore(0x20, rootSlot)
        mstore(0x00, value)
        result := iszero(iszero(sload(keccak256(0x00, 0x40))))
        break
    }
}

assembly {
    if iszero(value) { value := _ZERO_SENTINEL }
    result := not(0)
    let rootPacked := sload(rootSlot)
    for {} 1 {} {
        if iszero(shr(160, shl(160, rootPacked))) {
            if eq(shr(96, rootPacked), value) {
                result := 0
                break
            }
            if eq(shr(96, sload(add(rootSlot, 1))), value) {
                result := 1
                break
            }
            if eq(shr(96, sload(add(rootSlot, 2))), value) {
                result := 2
                break
            }
            break
        }
        mstore(0x20, rootSlot)
        mstore(0x00, value)
        result := sub(sload(keccak256(0x00, 0x40)), 1)
        break
    }
}
